import{_ as o,c as e,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Adicionar Contas: Canais Duplos OAuth e Refresh Token | Antigravity Tools","description":"Aprenda as duas maneiras de adicionar contas no Antigravity Tools. Através de autorização OAuth com um clique ou adição manual de Refresh Token, suporta importação em lote, lida com falhas de callback e valida o pool de contas.","frontmatter":{"title":"Adicionar Contas: Canais Duplos OAuth e Refresh Token | Antigravity Tools","sidebarTitle":"Adicione sua Conta Google","subtitle":"Adicionar Contas: Canais Duplos OAuth/Refresh Token e Melhores Práticas","description":"Aprenda as duas maneiras de adicionar contas no Antigravity Tools. Através de autorização OAuth com um clique ou adição manual de Refresh Token, suporta importação em lote, lida com falhas de callback e valida o pool de contas.","tags":["Gerenciamento de Contas","OAuth","refresh_token","Google","Melhores Práticas"],"prerequisite":["start-getting-started"],"duration":15,"order":4},"headers":[],"relativePath":"pt/lbjlaq/Antigravity-Manager/start/add-account/index.md","filePath":"pt/lbjlaq/Antigravity-Manager/start/add-account/index.md"}'),c={name:"pt/lbjlaq/Antigravity-Manager/start/add-account/index.md"};function d(i,a,n,s,l,u){return t(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="adicionar-contas-canais-duplos-oauth-refresh-token-e-melhores-praticas" tabindex="-1">Adicionar Contas: Canais Duplos OAuth/Refresh Token e Melhores Práticas <a class="header-anchor" href="#adicionar-contas-canais-duplos-oauth-refresh-token-e-melhores-praticas" aria-label="Permalink to &quot;Adicionar Contas: Canais Duplos OAuth/Refresh Token e Melhores Práticas&quot;">​</a></h1><p>No Antigravity Tools, &quot;adicionar conta&quot; significa escrever o <code>refresh_token</code> da conta Google no pool de contas local, permitindo que solicitações de proxy reverso subsequente usem em rotação. Você pode passar pela autorização OAuth com um clique, ou pode colar diretamente o <code>refresh_token</code> para adicionar manualmente.</p><h2 id="o-que-voce-podera-fazer-apos-completar" tabindex="-1">O que você poderá fazer após completar <a class="header-anchor" href="#o-que-voce-podera-fazer-apos-completar" aria-label="Permalink to &quot;O que você poderá fazer após completar&quot;">​</a></h2><ul><li>Usar OAuth ou Refresh Token para adicionar contas Google ao pool de contas do Antigravity Tools</li><li>Copiar/abrir manualmente o link de autorização, e automaticamente completar a adição após o callback ser bem-sucedido</li><li>Ao encontrar problemas como não conseguir obter <code>refresh_token</code>, callback não conectar com <code>localhost</code>, saber como lidar</li></ul><h2 id="seu-dilema-atual" tabindex="-1">Seu dilema atual <a class="header-anchor" href="#seu-dilema-atual" aria-label="Permalink to &quot;Seu dilema atual&quot;">​</a></h2><ul><li>Clicou em &quot;Autorização OAuth&quot; mas fica girando, ou navegador avisa <code>localhost refused to connect</code></li><li>Autorização bem-sucedida, mas avisa &quot;Não foi possível obter Refresh Token&quot;</li><li>Você só tem <code>refresh_token</code>, não sabe como importar em lote de uma vez</li></ul><h2 id="quando-usar-essa-tecnica" tabindex="-1">Quando usar essa técnica <a class="header-anchor" href="#quando-usar-essa-tecnica" aria-label="Permalink to &quot;Quando usar essa técnica&quot;">​</a></h2><ul><li>Você quer adicionar contas da maneira mais estável (priorizar OAuth)</li><li>Você se importa mais com portabilidade/backup (Refresh Token é mais adequado como &quot;ativo do pool de contas&quot;)</li><li>Você quer adicionar muitas contas, quer importar em lote <code>refresh_token</code> (suporta extração de texto/JSON)</li></ul><h2 id="🎒-preparacao-antes-de-comecar" tabindex="-1">🎒 Preparação antes de começar <a class="header-anchor" href="#🎒-preparacao-antes-de-comecar" aria-label="Permalink to &quot;🎒 Preparação antes de começar&quot;">​</a></h2><ul><li>Você já instalou e pode abrir o Antigravity Tools desktop</li><li>Você sabe onde fica a entrada: navegação lateral para página <code>Accounts</code> (veja rota em <code>source/lbjlaq/Antigravity-Manager/src/App.tsx</code>)</li></ul><div class="info custom-block"><p class="custom-block-title">Duas palavras-chave desta lição</p><p><strong>OAuth</strong>: Um processo &quot;pular para navegador e autorizar&quot;. Antigravity Tools inicia temporariamente um endereço de callback local (<code>http://localhost/127.0.0.1/[::1]:&lt;port&gt;/oauth-callback</code>, escolhido automaticamente baseado no monitoramento IPv4/IPv6 do sistema), espera o navegador voltar com <code>code</code> depois troca por token. (Implementação em <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs</code>)</p><p><strong>refresh_token</strong>: Um &quot;credencial que pode ser usado por longo tempo para renovar access_token&quot;. Este projeto ao adicionar conta usa ele para trocar access_token primeiro, depois puxar email real do Google e ignora o email que você inseriu no frontend. (Implementação em <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/commands/mod.rs</code>)</p></div><h2 id="ideia-principal" tabindex="-1">Ideia Principal <a class="header-anchor" href="#ideia-principal" aria-label="Permalink to &quot;Ideia Principal&quot;">​</a></h2><p>O &quot;adicionar conta&quot; do Antigravity Tools, no fundo, é para obter um <code>refresh_token</code> disponível, e escrever informações da conta no pool de contas local.</p><ul><li><strong>Canal OAuth</strong>: Aplicação gera link de autorização para você e monitora callback local; após autorização completada troca token automaticamente e salva conta (veja <code>prepare_oauth_url</code>, <code>start_oauth_login</code>, <code>complete_oauth_login</code>)</li><li><strong>Canal Refresh Token</strong>: Você cola diretamente o <code>refresh_token</code>, aplicação usa ele para renovar access_token, e obtém email real do Google para gravar (veja <code>add_account</code>)</li></ul><h2 id="siga-me" tabindex="-1">Siga-me <a class="header-anchor" href="#siga-me" aria-label="Permalink to &quot;Siga-me&quot;">​</a></h2><h3 id="passo-1-abra-o-dialogo-adicionar-conta" tabindex="-1">Passo 1: Abra o diálogo &quot;Adicionar Conta&quot; <a class="header-anchor" href="#passo-1-abra-o-dialogo-adicionar-conta" aria-label="Permalink to &quot;Passo 1: Abra o diálogo &quot;Adicionar Conta&quot;&quot;">​</a></h3><p><strong>Por que</strong> Todas as entradas de adição estão consolidadas na página <code>Accounts</code>.</p><p>Operação: entre na página <code>Accounts</code>, clique no botão <strong>Add Account</strong> no lado direito (componente: <code>AddAccountDialog</code>).</p><p><strong>Você deve ver</strong>: Surge um diálogo com 3 abas: <code>OAuth</code> / <code>Refresh Token</code> / <code>Import</code> (veja <code>source/lbjlaq/Antigravity-Manager/src/components/accounts/AddAccountDialog.tsx</code>).</p><h3 id="passo-2-primeiro-use-autorizacao-oauth-com-um-clique-recomendado" tabindex="-1">Passo 2: Primeiro use autorização OAuth com um clique (recomendado) <a class="header-anchor" href="#passo-2-primeiro-use-autorizacao-oauth-com-um-clique-recomendado" aria-label="Permalink to &quot;Passo 2: Primeiro use autorização OAuth com um clique (recomendado)&quot;">​</a></h3><p><strong>Por que</strong> Este é o caminho recomendado padrão do produto: deixa aplicação gerar link de autorização, abrir navegador automaticamente, e após callback completar automaticamente o salvamento.</p><ol><li>Mude para aba <code>OAuth</code>.</li><li>Primeiro copie o link de autorização: após o diálogo abrir, chamará automaticamente <code>prepare_oauth_url</code> para pré-gerar URL (chamada frontend em <code>AddAccountDialog.tsx:111-125</code>; backend gera e monitora em <code>oauth_server.rs</code>).</li><li>Clique <strong>Start OAuth</strong> (corresponde a frontend <code>startOAuthLogin()</code> / backend <code>start_oauth_login</code>), permite aplicação abrir navegador padrão e começar a esperar callback.</li></ol><p><strong>Você deve ver</strong>:</p><ul><li>Aparece um link de autorização copiável no diálogo (nome do evento: <code>oauth-url-generated</code>)</li><li>Navegador abre página de autorização Google; após autorização redireciona para um endereço local, e mostra &quot;Authorization Successful!&quot; (<code>oauth_success_html()</code>)</li></ul><h3 id="passo-3-quando-oauth-nao-completa-automaticamente-use-concluir-oauth-para-finalizar-manualmente" tabindex="-1">Passo 3: Quando OAuth não completa automaticamente, use &quot;Concluir OAuth&quot; para finalizar manualmente <a class="header-anchor" href="#passo-3-quando-oauth-nao-completa-automaticamente-use-concluir-oauth-para-finalizar-manualmente" aria-label="Permalink to &quot;Passo 3: Quando OAuth não completa automaticamente, use &quot;Concluir OAuth&quot; para finalizar manualmente&quot;">​</a></h3><p><strong>Por que</strong> O fluxo OAuth tem dois estágios: navegador autoriza obtendo <code>code</code>, depois aplicação usa <code>code</code> para trocar token. Mesmo se você não clicou &quot;Start OAuth&quot;, desde que você abriu manualmente o link de autorização e completou callback, o diálogo tentará finalizar automaticamente; se não conseguir, você pode clicar uma vez manualmente.</p><ol><li>Se você é &quot;copiou link para abrir em seu próprio navegador&quot; (em vez de navegador padrão), após callback de autorização voltar, aplicação receberá evento <code>oauth-callback-received</code>, e chamará automaticamente <code>completeOAuthLogin()</code> (veja <code>source/lbjlaq/Antigravity-Manager/src/components/accounts/AddAccountDialog.tsx:67-109</code>).</li><li>Se você não vê conclusão automática, clique <strong>Finish OAuth</strong> no diálogo (corresponde a backend <code>complete_oauth_login</code>).</li></ol><p><strong>Você deve ver</strong>: Diálogo avisa sucesso e fecha automaticamente; nova conta aparece na lista <code>Accounts</code>.</p><div class="tip custom-block"><p class="custom-block-title">Dica: se callback não conectar, priorize copiar link</p><p>Backend tentará monitorar simultaneamente IPv6 <code>::1</code> e IPv4 <code>127.0.0.1</code>, e escolherá <code>localhost/127.0.0.1/[::1]</code> como endereço de callback baseado na situação de monitoramento, principalmente para evitar falha de conexão causada por &quot;navegador resolvendo localhost para IPv6&quot;. (Veja <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs:53-113</code>)</p></div><h3 id="passo-4-adicione-manualmente-com-refresh-token-suporta-lote" tabindex="-1">Passo 4: Adicione manualmente com Refresh Token (suporta lote) <a class="header-anchor" href="#passo-4-adicione-manualmente-com-refresh-token-suporta-lote" aria-label="Permalink to &quot;Passo 4: Adicione manualmente com Refresh Token (suporta lote)&quot;">​</a></h3><p><strong>Por que</strong> Quando você não consegue obter <code>refresh_token</code> (ou você prefere &quot;ativo portátil&quot;), adicionar com Refresh Token é mais controlável.</p><ol><li>Mude para aba <code>Refresh Token</code>.</li><li>Cole o <code>refresh_token</code> na caixa de texto.</li></ol><p>Formatos de entrada suportados (frontend analisará e adicionará em lote):</p><table tabindex="0"><thead><tr><th>Tipo de entrada</th><th>Exemplo</th><th>Lógica de análise</th></tr></thead><tbody><tr><td>Texto de token puro</td><td><code>1//abc...</code></td><td>Extração por regex: <code>/1\\/\\/[a-zA-Z0-9_\\-]+/g</code> (veja <code>AddAccountDialog.tsx:213-220</code>)</td></tr><tr><td>Misturado em texto grande</td><td>Logs/texto exportado contém múltiplos <code>1//...</code></td><td>Extração em lote por regex e deduplicação (veja <code>AddAccountDialog.tsx:213-224</code>)</td></tr><tr><td>Array JSON</td><td><code>[{&quot;refresh_token&quot;:&quot;1//...&quot;}]</code></td><td>Analisa array e pega <code>item.refresh_token</code> (veja <code>AddAccountDialog.tsx:198-207</code>)</td></tr></tbody></table><p>Após clicar <strong>Confirm</strong>, diálogo chamará <code>onAdd(&quot;&quot;, token)</code> uma por uma baseado na quantidade de tokens (veja <code>AddAccountDialog.tsx:231-248</code>), finalmente chegando no backend <code>add_account</code>.</p><p><strong>Você deve ver</strong>:</p><ul><li>Diálogo mostra progresso em lote (ex: <code>1/5</code>)</li><li>Após sucesso, nova conta aparece na lista <code>Accounts</code></li></ul><h3 id="passo-5-confirme-pool-de-contas-disponivel" tabindex="-1">Passo 5: Confirme &quot;Pool de Contas Disponível&quot; <a class="header-anchor" href="#passo-5-confirme-pool-de-contas-disponivel" aria-label="Permalink to &quot;Passo 5: Confirme &quot;Pool de Contas Disponível&quot;&quot;">​</a></h3><p><strong>Por que</strong> Adição com sucesso não é igual a &quot;pode usar estável imediatamente&quot;. Backend após adição disparará automaticamente uma &quot;atualização de cota&quot;, e ao Proxy rodar tentará reload token pool, fazendo mudanças entrarem em vigor imediatamente.</p><p>Você pode confirmar com estes 2 sinais:</p><ol><li>Conta aparece na lista, e mostra email (email vem de backend <code>get_user_info</code>, não o email que você inseriu).</li><li>Informações de cota/assinatura da conta começam a atualizar (backend chamará automaticamente <code>internal_refresh_account_quota</code>).</li></ol><p><strong>Você deve ver</strong>: Após adicionar, não precisa clicar atualizar manualmente, conta começará a aparecer informações de cota (sucesso baseado no que a interface realmente exibe).</p><h2 id="ponto-de-verificacao-✅" tabindex="-1">Ponto de verificação ✅ <a class="header-anchor" href="#ponto-de-verificacao-✅" aria-label="Permalink to &quot;Ponto de verificação ✅&quot;">​</a></h2><ul><li>Pode ver email da nova conta na lista de contas</li><li>Não fica parado em estado &quot;loading&quot; além do tempo que você aceita (após callback OAuth completar deve finalizar rápido)</li><li>Se você está rodando Proxy, nova conta pode participar de agendamento rápido (backend tentará reload)</li></ul><h2 id="aviso-sobre-armadilhas" tabindex="-1">Aviso sobre armadilhas <a class="header-anchor" href="#aviso-sobre-armadilhas" aria-label="Permalink to &quot;Aviso sobre armadilhas&quot;">​</a></h2><h3 id="_1-oauth-avisa-nao-foi-possivel-obter-refresh-token" tabindex="-1">1) OAuth avisa &quot;Não foi possível obter Refresh Token&quot; <a class="header-anchor" href="#_1-oauth-avisa-nao-foi-possivel-obter-refresh-token" aria-label="Permalink to &quot;1) OAuth avisa &quot;Não foi possível obter Refresh Token&quot;&quot;">​</a></h3><p>Backend em <code>start_oauth_login/complete_oauth_login</code> verificará explicitamente se <code>refresh_token</code> existe; se não existir, retornará uma mensagem de erro com solução (veja <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/commands/mod.rs:45-56</code>).</p><p>Maneira de lidar sugerida pelo código-fonte:</p><ol><li>Abra <code>https://myaccount.google.com/permissions</code></li><li>Revogue permissão de <strong>Antigravity Tools</strong></li><li>Volte para aplicação e passe OAuth novamente</li></ol><blockquote><p>Você também pode mudar diretamente para o canal Refresh Token desta lição.</p></blockquote><h3 id="_2-navegador-avisa-localhost-refused-to-connect" tabindex="-1">2) Navegador avisa <code>localhost refused to connect</code> <a class="header-anchor" href="#_2-navegador-avisa-localhost-refused-to-connect" aria-label="Permalink to &quot;2) Navegador avisa `localhost refused to connect`&quot;">​</a></h3><p>Callback OAuth precisa que navegador solicite endereço de callback local. Para reduzir taxa de falha, backend:</p><ul><li>Tentará monitorar simultaneamente <code>127.0.0.1</code> e <code>::1</code></li><li>Quando ambos disponíveis usa <code>localhost</code>, caso contrário força usar <code>127.0.0.1</code> ou <code>[::1]</code></li></ul><p>Implementação correspondente em <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs:53-113</code>.</p><h3 id="_3-mudar-para-outra-aba-cancela-preparacao-oauth" tabindex="-1">3) Mudar para outra aba cancela preparação OAuth <a class="header-anchor" href="#_3-mudar-para-outra-aba-cancela-preparacao-oauth" aria-label="Permalink to &quot;3) Mudar para outra aba cancela preparação OAuth&quot;">​</a></h3><p>Quando diálogo muda de <code>OAuth</code> para outra aba, frontend chamará <code>cancelOAuthLogin()</code> e limpará URL (veja <code>AddAccountDialog.tsx:127-136</code>).</p><p>Se você está no processo de autorização, não mude de aba com pressa.</p><h3 id="_4-exemplos-corretos-errados-de-refresh-token" tabindex="-1">4) Exemplos corretos/errados de Refresh Token <a class="header-anchor" href="#_4-exemplos-corretos-errados-de-refresh-token" aria-label="Permalink to &quot;4) Exemplos corretos/errados de Refresh Token&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Exemplo</th><th>Será reconhecido</th><th>Motivo</th></tr></thead><tbody><tr><td><code>1//0gAbC...</code></td><td>✓</td><td>Atende regra de prefixo <code>1//</code> (veja <code>AddAccountDialog.tsx:215-219</code>)</td></tr><tr><td><code>ya29.a0...</code></td><td>✗</td><td>Não atende regra de extração frontend, será tratado como entrada inválida</td></tr></tbody></table><h2 id="resumo-da-licao" tabindex="-1">Resumo da lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da lição&quot;">​</a></h2><ul><li>OAuth: adequado para &quot;rápido&quot;, também suporta copiar link para seu navegador habitual e finalizar automático/manual</li><li>Refresh Token: adequado para &quot;estável&quot; e &quot;portátil&quot;, suporta extração em lote de texto/JSON <code>1//...</code></li><li>Quando não consegue obter <code>refresh_token</code>, revogue autorização seguindo aviso de erro e refaça, ou mude diretamente para Refresh Token</li></ul><h2 id="proximo-aviso-de-licao" tabindex="-1">Próximo aviso de lição <a class="header-anchor" href="#proximo-aviso-de-licao" aria-label="Permalink to &quot;Próximo aviso de lição&quot;">​</a></h2><p>Na próxima lição faremos algo mais sólido: transformar o pool de contas em &quot;ativo portátil&quot;.</p><blockquote><p>Vá aprender <strong><a href="./../backup-migrate/">Backup de Contas: Importar/Exportar, Migração a quente V1/DB</a></strong>.</p></blockquote><hr><h2 id="apendice-referencia-de-codigo-fonte" tabindex="-1">Apêndice: Referência de código-fonte <a class="header-anchor" href="#apendice-referencia-de-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência de código-fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir localização do código-fonte</strong></summary><blockquote><p>Atualizado em: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do arquivo</th><th>Linha</th></tr></thead><tbody><tr><td>Página Accounts monta diálogo de adição</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Accounts.tsx#L267-L731" target="_blank" rel="noreferrer"><code>src/pages/Accounts.tsx</code></a></td><td>267-731</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Evento de callback OAuth dispara <code>completeOAuthLogin()</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L67-L109" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>67-109</td></tr><tr><td>Análise em lote de Refresh Token e deduplicação</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L185-L268" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>185-268</td></tr><tr><td>Frontend chama comandos Tauri (add/OAuth/cancel)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/services/accountService.ts#L5-L91" target="_blank" rel="noreferrer"><code>src/services/accountService.ts</code></a></td><td>5-91</td></tr><tr><td>Backend add_account: ignora email, usa refresh_token para obter email real e gravar</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L19-L60" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>19-60</td></tr><tr><td>Backend OAuth: verifica falta de refresh_token e dá solução de revogação</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L38-L79" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>38-79</td></tr><tr><td>Server de callback OAuth: monitora simultaneamente IPv4/IPv6 e escolhe redirect_uri</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/oauth_server.rs#L43-L113" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/oauth_server.rs</code></a></td><td>43-113</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Nomes de eventos principais</strong>:</p><ul><li><code>oauth-url-generated</code>: backend envia para frontend após gerar URL OAuth (veja <code>oauth_server.rs:250-252</code>)</li><li><code>oauth-callback-received</code>: backend notifica frontend após receber callback e analisar code (veja <code>oauth_server.rs:177-180</code> / <code>oauth_server.rs:232-235</code>)</li></ul><p><strong>Comandos principais</strong>:</p><ul><li><code>prepare_oauth_url</code>: pré-gera link de autorização e inicia monitoramento de callback (veja <code>src-tauri/src/commands/mod.rs:469-473</code>)</li><li><code>start_oauth_login</code>: abre navegador padrão e espera callback (veja <code>src-tauri/src/commands/mod.rs:339-401</code>)</li><li><code>complete_oauth_login</code>: não abre navegador, apenas espera callback e completa troca de token (veja <code>src-tauri/src/commands/mod.rs:405-467</code>)</li><li><code>add_account</code>: usa refresh_token para gravar conta (veja <code>src-tauri/src/commands/mod.rs:19-60</code>)</li></ul></details>',67)])])}const h=o(c,[["render",d]]);export{p as __pageData,h as default};
